export class GroupDetailComponent {
  constructor(route, router, groupService, expenseService, fb, authService) {
    this.route = route;
    this.router = router;
    this.groupService = groupService;
    this.expenseService = expenseService;
    this.fb = fb;
    this.authService = authService;
    this.group = null;
    this.expenses = [];
    this.editingExpenseId = null;
    this.editLoading = false;
    this.editError = '';
    this.balances = [];
    this.transfers = [];
    this.currentUserId = null;
    this.myBalance = 0;
    this.toPay = [];
    this.toReceive = [];
    this.showExpenseForm = false;
    this.expenseLoading = false;
    this.inviteLoading = false;
    this.expenseError = '';
    this.inviteError = '';
    this.inviteSuccess = '';
    this.balancesLoading = false;
  }
  ngOnInit() {
    this.expenseForm = this.fb.group({
      description: ['', [Validators.required]],
      amount: ['', [Validators.required, Validators.min(0.01)]]
    });
    this.inviteForm = this.fb.group({
      email: ['', [Validators.required, Validators.email]]
    });
    this.editExpenseForm = this.fb.group({
      description: ['', [Validators.required]],
      amount: ['', [Validators.required, Validators.min(0.01)]]
    });
    this.route.params.subscribe(params => {
      const groupId = params['id'];
      this.loadGroupAndExpenses(groupId);
    });
    this.authService.currentUser$.subscribe(user => {
      this.currentUserId = user ? user.id : null;
    });
  }
  loadGroupAndExpenses(groupId) {
    this.groupService.getGroups().subscribe({
      next: response => {
        this.group = response.groups.find(g => g._id === groupId) || null;
        if (this.group) this.loadGroupBalances(this.group._id);
      },
      error: err => console.error('Error loading groups', err)
    });
    this.expenseService.getExpenses(groupId).subscribe({
      next: response => {
        this.expenses = response.expenses;
      },
      error: err => console.error('Error loading expenses', err)
    });
  }
  loadGroupBalances(groupId) {
    this.balancesLoading = true;
    this.groupService.getGroupSettlements(groupId).subscribe({
      next: response => {
        this.balances = response.balances;
        this.transfers = response.transfers || [];
        if ((!response.transfers || response.transfers.length === 0) && this.balances && this.balances.length) {
