    this.expenseService.createExpense(this.group._id, description, amount, this.group.members.map(m => m._id)).subscribe({
      next: () => {
        this.expenseForm.reset();
        this.showExpenseForm = false;
        this.expenseLoading = false;
        this.loadGroupAndExpenses(this.group._id);
      },
      error: err => {
        this.expenseError = err.error?.message || 'Failed to add expense';
        this.expenseLoading = false;
      }
    });
  }
  startEdit(expense) {
    this.editingExpenseId = expense._id;
    this.editError = '';
    this.editExpenseForm.setValue({
      description: expense.description,
      amount: expense.amount
    });
  }
  cancelEdit() {
    this.editingExpenseId = null;
    this.editExpenseForm.reset();
    this.editError = '';
  }
  submitEdit(expenseId) {
    if (this.editExpenseForm.invalid) return;
    this.editLoading = true;
    const {
      description,
      amount
    } = this.editExpenseForm.value;
    this.expenseService.updateExpense(expenseId, {
      description,
      amount
