      next: resp => {
        this.editLoading = false;
        this.editingExpenseId = null;
        this.loadGroupAndExpenses(this.group._id);
      },
      error: err => {
        this.editLoading = false;
        this.editError = err.error?.message || 'Failed to update expense';
      }
    });
  }
  confirmDelete(expenseId) {
